                      <td style={{ padding: '8px 12px', fontSize: 12, color: '#78716C' }}>{formatServerDate(s.date)}</td>
                      <td style={{ padding: '8px 12px', fontSize: 12 }}>{formatServerTime(s.clock_in)}</td>
                      <td style={{ padding: '8px 12px', fontSize: 12 }}>{s.clock_out ? formatServerTime(s.clock_out) : <span style={{ color: '#10B981', fontWeight: 700 }}>Active</span>}</td>
                      <td style={{ padding: '8px 12px', fontSize: 12, color: '#78716C' }}>{s.break_minutes || 0}m</td>
                      <td style={{ padding: '8px 12px', fontWeight: 700, color: '#3B82F6' }}>{s.actual_hours ? fmtHrs(s.actual_hours) : '—'}</td>
                      <td style={{ padding: '8px 12px' }}>
                        {s.overtime_hours > 0 ? (
                          <div>
                            <span style={{ color: s.overtime_approved ? '#10B981' : '#F59E0B', fontWeight: 700, fontSize: 12 }}>
